mapper.select:
SELECT * FROM (
	SELECT ROWNUM AS rn, sq.*
	FROM (
		SELECT jno, cid, title, content, deadline
		FROM job
		WHERE cid = #{cid}
		ORDER BY jno DESC
	) sq
)
WHERE rn > #{offset} AND rn <= #{offset} + #{pageSize}

mapper.update:
UPDATE job
SET title = #{title},
content = #{content},
deadline = #{deadline}
WHERE jno = #{jno}
